SELECT *
FROM associations
WHERE active_status = 1;

SELECT COUNT(*)
FROM associations
WHERE active_status = 1 AND association_id > 0 AND membership_cap > 0;

SELECT COUNT(*)
FROM member_associations
WHERE association_id = 1;

SELECT members.membership_status, COUNT(*) as active_count
FROM members 
WHERE members.membership_status = 'active';
